import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../App';
import './WorkshopStatusPage.css';

const MOCK_WORKSHOPS = [
  { id: 1, type: 'Python', date: '2026-05-10', instructor: 'Dr. Anil Verma', status: 'accepted', attendees: 32 },
  { id: 2, type: 'Scilab', date: '2026-06-15', instructor: 'Prof. Sunita Rao', status: 'pending', attendees: 28 },
  { id: 3, type: 'R', date: '2026-03-01', instructor: 'Dr. Priya Nair', status: 'completed', attendees: 45 },
  { id: 4, type: 'eSim', date: '2026-04-20', instructor: null, status: 'rejected', attendees: 18 },
];

const STATUS_CONFIG = {
  accepted: { label: 'Confirmed', badge: 'badge-success', icon: '✓' },
  pending: { label: 'Under Review', badge: 'badge-warning', icon: '⏳' },
  completed: { label: 'Completed', badge: 'badge-info', icon: '🏁' },
  rejected: { label: 'Declined', badge: 'badge-danger', icon: '✕' },
};

export default function WorkshopStatusPage() {
  const { user } = useAuth();
  const [tab, setTab] = useState('all');

  if (!user) {
    return (
      <div className="container" style={{ padding: '80px 20px', textAlign: 'center' }}>
        <div style={{ fontSize: '48px', marginBottom: '16px' }}>🔒</div>
        <h2>Sign in required</h2>
        <p style={{ color: 'var(--text-muted)', marginBottom: '24px' }}>
          You must be signed in to view your workshops.
        </p>
        <Link to="/login" className="btn btn-primary">Sign in</Link>
      </div>
    );
  }

  const tabs = [
    { key: 'all', label: 'All', count: MOCK_WORKSHOPS.length },
    { key: 'pending', label: 'Pending', count: MOCK_WORKSHOPS.filter(w => w.status === 'pending').length },
    { key: 'accepted', label: 'Confirmed', count: MOCK_WORKSHOPS.filter(w => w.status === 'accepted').length },
    { key: 'completed', label: 'Completed', count: MOCK_WORKSHOPS.filter(w => w.status === 'completed').length },
    { key: 'rejected', label: 'Declined', count: MOCK_WORKSHOPS.filter(w => w.status === 'rejected').length },
  ];

  const filtered = tab === 'all' ? MOCK_WORKSHOPS : MOCK_WORKSHOPS.filter(w => w.status === tab);

  return (
    <div className="ws-page">
      <div className="container">
        <div className="page-header ws-page-header">
          <div>
            <h1>My Workshops</h1>
            <p>Track the status of all your workshop proposals</p>
          </div>
          <Link to="/propose" className="btn btn-primary">
            + Propose New
          </Link>
        </div>

        {/* Stats mini bar */}
        <div className="ws-stats-row" role="list" aria-label="Workshop summary">
          {tabs.slice(1).map(t => {
            const cfg = STATUS_CONFIG[t.key];
            return (
              <div key={t.key} className="ws-stat" role="listitem">
                <span className={`badge ${cfg.badge}`}>{cfg.icon} {cfg.label}</span>
                <span className="ws-stat-count">{t.count}</span>
              </div>
            );
          })}
        </div>

        {/* Tab bar */}
        <div className="ws-tabs" role="tablist" aria-label="Filter workshops by status">
          {tabs.map(t => (
            <button
              key={t.key}
              className={`ws-tab${tab === t.key ? ' active' : ''}`}
              role="tab"
              aria-selected={tab === t.key}
              onClick={() => setTab(t.key)}
            >
              {t.label}
              {t.count > 0 && <span className="ws-tab-count">{t.count}</span>}
            </button>
          ))}
        </div>

        {/* Workshop cards */}
        {filtered.length === 0 ? (
          <div className="ws-empty" role="status">
            <span>📭</span>
            <h3>No workshops here</h3>
            <p>You don't have any {tab !== 'all' ? tab : ''} workshops yet.</p>
            <Link to="/propose" className="btn btn-outline" style={{ marginTop: '16px' }}>
              Propose a Workshop
            </Link>
          </div>
        ) : (
          <div className="ws-list" role="list" aria-label={`${tab} workshops`}>
            {filtered.map(w => {
              const cfg = STATUS_CONFIG[w.status];
              const dateFormatted = new Date(w.date).toLocaleDateString('en-IN', {
                weekday: 'short', year: 'numeric', month: 'short', day: 'numeric'
              });
              return (
                <div key={w.id} className="ws-card card" role="listitem">
                  <div className="ws-card-left">
                    <div className="ws-card-name">{w.type}</div>
                    <div className="ws-card-meta">
                      <span>📅 {dateFormatted}</span>
                      {w.instructor && <span>👤 {w.instructor}</span>}
                      <span>👥 {w.attendees} attendees</span>
                    </div>
                  </div>
                  <div className="ws-card-right">
                    <span className={`badge ${cfg.badge}`}>{cfg.icon} {cfg.label}</span>
                    {w.status === 'accepted' && (
                      <Link to={`/workshop-types/${w.id}`} className="btn btn-outline btn-sm">
                        View Details
                      </Link>
                    )}
                    {w.status === 'rejected' && (
                      <span className="ws-rejection-note">
                        Contact FOSSEE for details
                      </span>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}
